'use strict';

function renderTable(rows, options) {
  // Find max width for each column
  const colWidths = rows[0].map(() => 0);
  rows.forEach(row => {
    row.forEach((cell, i) => {
      colWidths[i] = Math.max(colWidths[i], cell.length);
    });
  });

  const align = options?.align || Array(colWidths.length).fill('left');

  // Format each row
  const lines = rows.map((row, rowIndex) => {
    const formatted = row.map((cell, i) => {
      const isLast = i === row.length - 1;

      if (align[i] === 'right') {
        return cell.padStart(colWidths[i]);
      } else {
        if (isLast) {
          return cell;
        }
        return cell.padEnd(colWidths[i]);
      }
    }).join(' ');

    // Add header separator after first row if options.header is true
    if (options?.header && rowIndex === 0) {
      return [formatted, '-'.repeat(formatted.length)];
    }
    return [formatted];
  }).flat();

  return lines.join('\n');
}

function renderTableLegacy(rows) {
  return renderTable(rows);
}

module.exports = {
  renderTable,
  renderTableLegacy,
};

