const { renderTable, renderTableLegacy } = require('./src/index.js');

// Stage 1: Basic renderTable
const stage1 = renderTable([['id','name'],['1','Ada Lovelace'],['42','Bo']]);
const expected1 = 'id name\n1  Ada Lovelace\n42 Bo';
console.log('Stage 1 Test:');
console.log('Expected:', JSON.stringify(expected1));
console.log('Got:     ', JSON.stringify(stage1));
console.log('Pass:', stage1 === expected1);
console.log();

// Stage 2: Right alignment
const stage2 = renderTable([['id','qty'],['7','100'],['1234','5']], {align:['right','right']});
const expected2 = '  id qty\n   7 100\n1234   5';
console.log('Stage 2 Test:');
console.log('Expected:', JSON.stringify(expected2));
console.log('Got:     ', JSON.stringify(stage2));
console.log('Pass:', stage2 === expected2);
console.log();

// Stage 3: Header
const stage3 = renderTable([['id','name'],['1','Bo']], {header:true});
const expected3 = 'id name\n-------\n1  Bo';
console.log('Stage 3 Test:');
console.log('Expected:', JSON.stringify(expected3));
console.log('Got:     ', JSON.stringify(stage3));
console.log('Pass:', stage3 === expected3);
console.log();

// Stage 1 Backward Compatibility
const legacy = renderTableLegacy([['id','name'],['1','Ada Lovelace'],['42','Bo']]);
console.log('Legacy Test:');
console.log('Expected:', JSON.stringify(expected1));
console.log('Got:     ', JSON.stringify(legacy));
console.log('Pass:', legacy === expected1);
"

